<?php
declare(strict_types=1);
require_once dirname(__DIR__) . '/includes/cms.php';
if(($_SERVER['REQUEST_METHOD']??'GET')!=='POST'||!validarTokenCsrf(isset($_POST['csrf_token'])?(string)$_POST['csrf_token']:null)){cmsFlash('error','Solicitud inválida.');header('Location:index.php');exit;}
$id=cmsId($_POST['id']??0);$accion=(string)($_POST['accion']??'');$pdo=obtenerConexion();
try{$pdo->beginTransaction();$q=$pdo->prepare('SELECT id,estado FROM noticias WHERE id=:id AND deleted_at IS NULL FOR UPDATE');$q->execute(['id'=>$id]);$n=$q->fetch();if(!$n)throw new RuntimeException('La noticia no existe.');if($accion==='publicar')$pdo->prepare("UPDATE noticias SET estado='publicado',activo=1,fecha_publicacion=COALESCE(fecha_publicacion,NOW()) WHERE id=:id")->execute(['id'=>$id]);elseif($accion==='despublicar')$pdo->prepare("UPDATE noticias SET estado='borrador' WHERE id=:id")->execute(['id'=>$id]);elseif($accion==='toggle')$pdo->prepare('UPDATE noticias SET activo=1-activo WHERE id=:id')->execute(['id'=>$id]);elseif($accion==='eliminar')$pdo->prepare("UPDATE noticias SET deleted_at=NOW(),eliminado_por=:admin,activo=0,estado='borrador' WHERE id=:id")->execute(['admin'=>(int)$_SESSION['usuario_id'],'id'=>$id]);else throw new RuntimeException('Acción no válida.');registrarAuditoria(['actor_user_id'=>(int)$_SESSION['usuario_id'],'event_type'=>'news.'.$accion,'module'=>'news','entity_type'=>'news','entity_id'=>$id,'action'=>$accion,'result'=>'success','description'=>'Se cambió el estado de una noticia.'],$pdo);$pdo->commit();cmsFlash('exito','Noticia actualizada.');}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log('Acción noticia: '.$e->getMessage());cmsFlash('error','No fue posible actualizar la noticia.');}header('Location:index.php');exit;
